local TD = TD.td1madao["ydj_dst_td1madao"] TD.createFn("live", function(v)     if TD.server() then         return v and v.components and v.components.health and v.components.health.IsDead and not v.components.health:IsDead()     end     return v and v.replica and v.replica.health and v.replica.health._isdead and v.replica.health._isdead.value and not v.replica.health._isdead:value() end) TD.createFn("die", function(v)     if TD.server() then         return v and v.components.health and v.components.health.IsDead and v.components.health:IsDead()     end     return v and v.replica and v.replica.health and v.replica.health._isdead and v.replica.health._isdead.value and v.replica.health._isdead:value() end) TD.createFn("player_init", function(inst)     if not inst or not inst.HasTag or not inst:HasTag("player") then         return     end     if not inst:HasTag("playerghost") and TD.live(inst) then         inst.replica.health:SetIsDead(false)     end     if inst.replica and inst.replica.combat and inst.replica.combat._attackrange and (not inst.replica.combat._attackrange:value() or inst.replica.combat._attackrange:value() <= 1) then         inst.replica.combat._attackrange:set(2)     end end) 